def parse_entity(payload):
    if not isinstance(payload, dict):
        return None
    if "id" not in payload or "dept" not in payload:
        return None
    return {"id": payload["id"], "dept": payload["dept"]}
print(parse_entity({"id": "C001", "dept": "Lima", "extra": 1}))
print(parse_entity({"id": "C001"}))

